SELECT state_name
FROM states
WHERE population_density = (SELECT MAX(population_density) FROM states);

SELECT COUNT(*) AS total_states
FROM states
WHERE region = 'Northeast';

SELECT state_name
FROM states
WHERE population_density = (
    SELECT MAX(population_density)
    FROM states
);

SELECT state_name, region 
FROM states 
WHERE population_density = (
    SELECT MAX(population_density) 
    FROM states
);
